import React, { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import VehicleForm from "../component/VehicleForm";
import VehicleTable from "../component/VehicleTable";
import MapComponent from "../component/MapComponent";
import AnalyticsChart from "../component/AnalyticsChart";
import { connectWebSocket, disconnectWebSocket } from "../services/websocket";

export default function Dashboard() {
const [vehicles, setVehicles] = useState([
{ id: 1, licensePlate: "KA-01-AB-1234", location: "37.7749,-122.4194", status: "active", mileage: 5300, fuelLevel: 65 },
{ id: 2, licensePlate: "MH-12-XY-4321", location: "37.7849,-122.4094", status: "idle", mileage: 8100, fuelLevel: 48 },
{ id: 3, licensePlate: "DL-05-CQ-7777", location: "37.7649,-122.4294", status: "active", mileage: 2500, fuelLevel: 72 },
]);

useEffect(() => {
const onMessage = (msg) => {
if (msg && Array.isArray(msg.vehicles)) {
setVehicles(msg.vehicles);
}
};
connectWebSocket(onMessage);
return () => disconnectWebSocket();
}, []);

const metrics = useMemo(() => {
return {
vehicles: vehicles.length,
activeTrips: 6,
alerts: 2,
};
}, [vehicles]);

const handleAdd = (v) => {
setVehicles((prev) => {
const id = prev.length ? Math.max(...prev.map((x) => x.id || 0)) + 1 : 1;
return [...prev, { ...v, id }];
});
};

return (
<div className="g-auth-bg">
<div className="g-auth-card" style={{ maxWidth: 980, alignItems: "stretch" }}>
<div className="g-auth-logo" style={{ justifyContent: "flex-start" }}>
<span className="g-dot g-blue" />
<span className="g-dot g-red" />
<span className="g-dot g-yellow" />
<span className="g-dot g-green" />
<span className="g-brand">NeuroFleetX</span>
</div>

    <h1 className="g-title">Dashboard</h1>
    <p className="g-subtitle">Live fleet overview</p>

    <div style={{ width: "100%", marginTop: 8 }}>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 12 }}>
        <div style={{ padding: 12, border: "1px solid #dadce0", borderRadius: 8 }}>
          <div style={{ fontSize: 12, color: "#5f6368" }}>Vehicles</div>
          <div style={{ fontSize: 22, fontWeight: 800 }}>{metrics.vehicles}</div>
        </div>
        <div style={{ padding: 12, border: "1px solid #dadce0", borderRadius: 8 }}>
          <div style={{ fontSize: 12, color: "#5f6368" }}>Active trips</div>
          <div style={{ fontSize: 22, fontWeight: 800 }}>{metrics.activeTrips}</div>
        </div>
        <div style={{ padding: 12, border: "1px solid #dadce0", borderRadius: 8 }}>
          <div style={{ fontSize: 12, color: "#5f6368" }}>Alerts</div>
          <div style={{ fontSize: 22, fontWeight: 800, color: "#c62828" }}>{metrics.alerts}</div>
        </div>
      </div>
    </div>

    <div style={{ marginTop: 16, width: "100%", display: "grid", gridTemplateColumns: "1.2fr 1fr", gap: 16 }}>
      <div>
        <div style={{ fontWeight: 700, marginBottom: 8 }}>Map</div>
        <MapComponent vehicles={vehicles} />
      </div>
      <div style={{ height: 420 }}>
        <div style={{ fontWeight: 700, marginBottom: 8 }}>Analytics</div>
        <div style={{ height: "100%", border: "1px solid #dadce0", borderRadius: 8, padding: 8 }}>
          <AnalyticsChart vehicles={vehicles} />
        </div>
      </div>
    </div>

    <div style={{ marginTop: 16, width: "100%", display: "grid", gridTemplateColumns: "1fr 1.3fr", gap: 16 }}>
      <div style={{ border: "1px solid #dadce0", borderRadius: 8 }}>
        <div style={{ padding: 8, fontWeight: 700, borderBottom: "1px solid #dadce0" }}>Add Vehicle</div>
        <VehicleForm onAdd={handleAdd} />
      </div>
      <div style={{ border: "1px solid #dadce0", borderRadius: 8, padding: 8, overflowX: "auto" }}>
        <div style={{ fontWeight: 700, marginBottom: 8 }}>Vehicles</div>
        <VehicleTable vehicles={vehicles} />
      </div>
    </div>

    <div className="g-actions" style={{ marginTop: 18 }}>
      <Link className="g-btn" to="/">Sign out</Link>
    </div>
  </div>
</div>
);
}
